"""
TofuSoup Workenv Matrix Testing
===============================
Functionality for testing multiple tool version combinations.
"""

import asyncio
from dataclasses import dataclass, field
import itertools
import json
import pathlib
import tempfile
from typing import Any

from rich.console import Console
from rich.progress import (
    BarColumn,
    Progress,
    SpinnerColumn,
    TextColumn,
    TimeElapsedColumn,
)

from pyvider.telemetry import logger

from ..config import WorkenvConfig
from ..managers.factory import get_tool_manager

console = Console()


@dataclass
class MatrixCombination:
    """Represents a specific combination of tool versions."""

    tools: dict[str, str] = field(default_factory=dict)

    def __str__(self) -> str:
        tool_strs = [f"{tool}:{version}" for tool, version in self.tools.items()]
        return f"[{', '.join(tool_strs)}]"

    def to_dict(self) -> dict:
        return {"tools": self.tools}

    @classmethod
    def from_dict(cls, data: dict) -> "MatrixCombination":
        return cls(tools=data.get("tools", {}))


@dataclass
class MatrixResult:
    """Result from testing a matrix combination."""

    combination: MatrixCombination
    success: bool
    duration_seconds: float = 0.0
    error_message: str | None = None
    harness_results: dict[str, Any] = field(default_factory=dict)

    def to_dict(self) -> dict:
        return {
            "combination": self.combination.to_dict(),
            "success": self.success,
            "duration_seconds": self.duration_seconds,
            "error_message": self.error_message,
            "harness_results": self.harness_results,
        }


class VersionMatrix:
    """Manages version matrix testing for TofuSoup workenv."""

    def __init__(self, base_tools: dict[str, str], config: WorkenvConfig):
        self.config = config
        self.base_tools = base_tools
        self.parallel_jobs = config.get_setting("matrix_parallel_jobs", 4)
        self.timeout_minutes = config.get_setting("matrix_timeout_minutes", 30)

        # Get matrix configuration from soup.toml
        self.matrix_config = config.get_matrix_config()

    def generate_combinations(self) -> list[MatrixCombination]:
        """Generate all combinations for matrix testing."""
        # Start with base tools
        tool_versions = {}

        for tool_name, base_version in self.base_tools.items():
            # Get additional versions to test for this tool
            matrix_versions = self.matrix_config.get("versions", {}).get(tool_name, [])

            # Combine base version with matrix versions
            all_versions = [base_version]
            if matrix_versions:
                all_versions.extend(matrix_versions)

            # Remove duplicates while preserving order
            tool_versions[tool_name] = list(dict.fromkeys(all_versions))

        # Generate all combinations
        combinations = []

        if not tool_versions:
            return combinations

        tool_names = list(tool_versions.keys())
        version_lists = [tool_versions[tool] for tool in tool_names]

        for version_combo in itertools.product(*version_lists):
            combo_dict = dict(zip(tool_names, version_combo, strict=False))
            combinations.append(MatrixCombination(tools=combo_dict))

        logger.info(f"Generated {len(combinations)} matrix combinations")
        return combinations

    async def run_conformance_tests(self) -> dict[str, Any]:
        """Run conformance tests across all matrix combinations."""
        combinations = self.generate_combinations()

        if not combinations:
            return {
                "success_count": 0,
                "failure_count": 0,
                "results": [],
                "message": "No combinations to test",
            }

        console.print(
            f"\\n[bold cyan]Running {len(combinations)} matrix combinations...[/bold cyan]"
        )

        results = []
        semaphore = asyncio.Semaphore(self.parallel_jobs)

        async def test_combination(combo: MatrixCombination) -> MatrixResult:
            async with semaphore:
                return await self._test_single_combination(combo)

        # Run all combinations with progress tracking
        with Progress(
            SpinnerColumn(),
            TextColumn("[progress.description]{task.description}"),
            BarColumn(),
            TextColumn("[progress.percentage]{task.percentage:>3.0f}%"),
            TimeElapsedColumn(),
            console=console,
        ) as progress:
            task = progress.add_task("Testing combinations...", total=len(combinations))

            tasks = [test_combination(combo) for combo in combinations]

            for coro in asyncio.as_completed(tasks):
                result = await coro
                results.append(result)
                progress.advance(task)

                # Update progress description with latest result
                status = "✅" if result.success else "❌"
                progress.update(
                    task,
                    description=f"Testing combinations... {status} {result.combination}",
                )

        # Aggregate results
        success_count = sum(1 for r in results if r.success)
        failure_count = len(results) - success_count

        return {
            "success_count": success_count,
            "failure_count": failure_count,
            "results": [r.to_dict() for r in results],
            "total_combinations": len(combinations),
            "parallel_jobs": self.parallel_jobs,
        }

    async def _test_single_combination(
        self, combination: MatrixCombination
    ) -> MatrixResult:
        """Test a single tool version combination."""
        import time

        start_time = time.time()

        try:
            logger.debug(f"Testing combination: {combination}")

            # Install all tools in this combination
            await self._install_combination_tools(combination)

            # Run harness tests for this combination
            harness_results = await self._run_harness_tests(combination)

            # Check if all harness tests passed
            success = all(
                result.get("success", False) for result in harness_results.values()
            )

            duration = time.time() - start_time

            return MatrixResult(
                combination=combination,
                success=success,
                duration_seconds=duration,
                harness_results=harness_results,
            )

        except Exception as e:
            duration = time.time() - start_time
            logger.error(f"Matrix combination {combination} failed: {e}")

            return MatrixResult(
                combination=combination,
                success=False,
                duration_seconds=duration,
                error_message=str(e),
            )

    async def _install_combination_tools(self, combination: MatrixCombination) -> None:
        """Install all tools for a specific combination."""
        for tool_name, version in combination.tools.items():
            manager = get_tool_manager(tool_name, self.config)
            if not manager:
                raise Exception(f"No manager available for tool: {tool_name}")

            # Check if already installed
            current_version = manager.get_installed_version()
            if current_version == version:
                binary_path = manager.get_current_binary_path()
                if binary_path and binary_path.exists():
                    continue  # Already installed

            # Install the specific version
            logger.debug(f"Installing {tool_name} {version} for matrix testing")
            await asyncio.get_event_loop().run_in_executor(
                None,
                manager.install_version,
                version,
                False,  # not dry_run
            )

    async def _run_harness_tests(
        self, combination: MatrixCombination
    ) -> dict[str, Any]:
        """Run harness tests for a tool combination."""
        # Get enabled harnesses from configuration
        enabled_harnesses = self.matrix_config.get("harness", ["go.cty", "python.cty"])

        harness_results = {}

        for harness_name in enabled_harnesses:
            try:
                result = await self._run_single_harness(harness_name, combination)
                harness_results[harness_name] = result

            except Exception as e:
                logger.error(f"Harness {harness_name} failed for {combination}: {e}")
                harness_results[harness_name] = {"success": False, "error": str(e)}

        return harness_results

    async def _run_single_harness(
        self, harness_name: str, combination: MatrixCombination
    ) -> dict[str, Any]:
        """Run a single harness test."""
        # Create temporary test environment
        with tempfile.TemporaryDirectory() as temp_dir:
            temp_path = pathlib.Path(temp_dir)

            # Set up environment variables for the tool versions
            env_vars = self._get_harness_environment(combination, temp_path)

            # Run the harness test
            if harness_name.startswith("go."):
                return await self._run_go_harness(harness_name, temp_path, env_vars)
            elif harness_name.startswith("python."):
                return await self._run_python_harness(harness_name, temp_path, env_vars)
            else:
                raise Exception(f"Unknown harness type: {harness_name}")

    def _get_harness_environment(
        self, combination: MatrixCombination, workspace: pathlib.Path
    ) -> dict[str, str]:
        """Get environment variables for harness execution."""
        env = {}

        for tool_name, version in combination.tools.items():
            manager = get_tool_manager(tool_name, self.config)
            if manager:
                binary_path = manager.get_binary_path(version)
                if binary_path.exists():
                    # Add tool-specific environment variables
                    if tool_name == "terraform":
                        env["TERRAFORM_BINARY"] = str(binary_path)
                    elif tool_name == "tofu":
                        env["TOFU_BINARY"] = str(binary_path)
                    elif tool_name == "go":
                        env["GO_BINARY"] = str(binary_path)
                        # Set GOROOT for Go
                        goroot = manager.get_goroot(version)
                        if goroot.exists():
                            env["GOROOT"] = str(goroot)
                    elif tool_name == "uv":
                        env["UV_BINARY"] = str(binary_path)

        # Set workspace directory
        env["WORKENV_TEST_WORKSPACE"] = str(workspace)

        return env

    async def _run_go_harness(
        self, harness_name: str, workspace: pathlib.Path, env: dict[str, str]
    ) -> dict[str, Any]:
        """Run a Go-based harness test."""
        # For now, this is a simplified implementation
        # In a real implementation, this would invoke the actual Go harness

        import asyncio

        # Simulate running a Go harness test
        go_binary = env.get("GO_BINARY")
        if not go_binary:
            raise Exception("Go binary not available for harness testing")

        # Create a simple test command
        cmd = [go_binary, "version"]

        try:
            process = await asyncio.create_subprocess_exec(
                *cmd,
                env=env,
                stdout=asyncio.subprocess.PIPE,
                stderr=asyncio.subprocess.PIPE,
                cwd=workspace,
            )

            stdout, stderr = await asyncio.wait_for(
                process.communicate(), timeout=self.timeout_minutes * 60
            )

            success = process.returncode == 0

            return {
                "success": success,
                "stdout": stdout.decode() if stdout else "",
                "stderr": stderr.decode() if stderr else "",
                "returncode": process.returncode,
            }

        except TimeoutError:
            return {
                "success": False,
                "error": f"Harness {harness_name} timed out after {self.timeout_minutes} minutes",
            }

    async def _run_python_harness(
        self, harness_name: str, workspace: pathlib.Path, env: dict[str, str]
    ) -> dict[str, Any]:
        """Run a Python-based harness test."""
        # For now, this is a simplified implementation
        # In a real implementation, this would invoke the actual Python harness

        import asyncio

        # Simulate running a Python harness test
        uv_binary = env.get("UV_BINARY")
        if not uv_binary:
            raise Exception("UV binary not available for Python harness testing")

        # Create a simple test command
        cmd = [uv_binary, "--version"]

        try:
            process = await asyncio.create_subprocess_exec(
                *cmd,
                env=env,
                stdout=asyncio.subprocess.PIPE,
                stderr=asyncio.subprocess.PIPE,
                cwd=workspace,
            )

            stdout, stderr = await asyncio.wait_for(
                process.communicate(), timeout=self.timeout_minutes * 60
            )

            success = process.returncode == 0

            return {
                "success": success,
                "stdout": stdout.decode() if stdout else "",
                "stderr": stderr.decode() if stderr else "",
                "returncode": process.returncode,
            }

        except TimeoutError:
            return {
                "success": False,
                "error": f"Harness {harness_name} timed out after {self.timeout_minutes} minutes",
            }

    def save_results(self, results: dict[str, Any], output_path: pathlib.Path) -> None:
        """Save matrix test results to a file."""
        with open(output_path, "w") as f:
            json.dump(results, f, indent=2)

        logger.info(f"Matrix test results saved to: {output_path}")

    def load_results(self, input_path: pathlib.Path) -> dict[str, Any]:
        """Load matrix test results from a file."""
        with open(input_path) as f:
            return json.load(f)


